VALUES
  ('heelevel3-7c4986e7-moex-00015', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-114-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '甲公司有兩種股份流通在外，普通股每股面額$10，流通在外400,000股；特別股每股面額$20， 流通在外50,000股。特別股為累積特別股，股利率8%，可部分參加至14%，已積欠3年股 利。若甲公司宣告發放$800,000現金股利，則特別股與普通股各可分配多少股利？', '["特別股股利$320,000、普通股股利$480,000", "特別股股利$352,000、普通股股利$448,000", "特別股股利$380,000、普通股股利$420,000", "特別股股利$400,000、普通股股利$400,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:24+00:00", "source_pdf_sha1": "3919d42dceee", "answer_pdf_sha1": "55ed3776824a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "223", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00016', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-114-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '甲公司因其金融資產的經營模式發生改變，擬將原分類為按攤銷後成本衡量之金融資產重分類 為透過損益按公允價值衡量之金融資產。下列那些項目是甲公司進行重分類時須作之會計處', '["以重分類日公允價值重新衡量該金融資產", "公允價值與攤銷後成本間的差額認列重分 類損益", "備抵損失轉列為其他綜合損益", "繼續使用原先的原始市場利率進行溢折價攤銷"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:24+00:00", "source_pdf_sha1": "3919d42dceee", "answer_pdf_sha1": "55ed3776824a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "223", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00017', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-114-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '甲公司因業務調整而規劃裁員80人，故於X1年10月1日宣布將於6個月內（截至X2年3 月31日）減少80名員工，自願離職者將給予$50,000離職金，然若屆時自願離職者不足80 人，則將解聘部分員工以便使總離職人數達80人，被解聘者可得$20,000離職金。甲公司估 計將有30人自願離職，其餘50人則需以解聘方式為之。截至X1年底，已有5名員工自願 離職，並已領取離職金。X1年底，甲公司資產負債表應列報離職福利負債為多少？', '["$2,500,000", "$2,250,000", "$1,600,000", "$1,500,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:24+00:00", "source_pdf_sha1": "3919d42dceee", "answer_pdf_sha1": "55ed3776824a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "223", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00018', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-114-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '甲公司在 X1 年 1 月 1 日向乙銀行借款$800,000，借款利率 6%，每年年底付息，X3 年底到 期，該借款之有效利率為6%。甲公司在X2年底勉強付清當年利息後，以財務困難為由向乙 銀行申請債務協商。經雙方協商後，乙銀行同意將本金降為$700,000，借款利率調降為2%， 且到期日展延至X5年12月31日。假設協商完成時市場利率為10%，3年期利率為6%及10% 的複利現值因子與年金現值因子如下表所示。甲公司應認列多少債務協商損益？ 6% 10% 複利現值因子 0.8396 0.7513 年金現值因子 2.6730 2.4869', '["利益$100,000", "利益$174,858", "利益$202,000", "利益$239,273 22340"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:24+00:00", "source_pdf_sha1": "3919d42dceee", "answer_pdf_sha1": "55ed3776824a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "223", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00019', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-114-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '甲公司於 X1 年 1 月 1 日開立票據面額$800,000 向乙銀行借款$800,000，該票據票面利率 10%，每年12月31日付息，到期日為X3年12月31日。X3年底，甲公司因資金調度困難， 無法支付當期利息與本金，經乙銀行同意甲公司以其車輛抵償全部債務。該車輛之原始成本 為$1,540,000，累計折舊$750,000，公允價值為$850,000。甲公司除列負債之損益為多少？', '["除列負債損失$50,000", "除列負債利益$30,000", "除列負債利益$60,000", "除列負債利益$90,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:24+00:00", "source_pdf_sha1": "3919d42dceee", "answer_pdf_sha1": "55ed3776824a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "223", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00020', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-114-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', 'X1年1月1日，甲公司響應政府之減碳政策而添購一套除碳設備，並獲得$5,000,000之低利 政府貸款，年息2%，每年年底付息，貸款期間為5年，市場利率為5%。假設甲公司將遞延 政府補助利益認列為負債，且除碳設備採直線法提列折舊，無殘值，使用年限為10年。已 知利率5%，5期之複利現值因子為0.7835，年金現值因子為4.3295。下列有關甲公司之敘述 何者正確？', '["X1年應認列政府補助利益$649,550", "X1年底遞延政府補助利益餘額為$584,595", "獲得政府貸款時應認列遞延政府補助利益$750,000", "X2年底資產負債表列報，遞延政府補助利益－非流動$519,640"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:24+00:00", "source_pdf_sha1": "3919d42dceee", "answer_pdf_sha1": "55ed3776824a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "223", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00021', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-114-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '甲公司自 X1 年起開始銷售空氣清淨機並提供為期一年的保證型保固，自銷售日起一年內， 若因產品製造瑕疵發生故障，均提供免費維修。甲公司評估保固期內因輕微瑕疵而需進行維 修之機率為4%，平均維修費用約$80；因重大瑕疵而需維修之機率為0.3%，平均維修費用約 $500。甲公司在X1年共售出5,000台空氣清淨機，實際發生維修支出$15,300。下列何者為 甲公司在X1年財務報表應列報之內容？', '["保固費用$15,300、保固負債準備$0", "保固費用$16,000、保固負債準備$7,500", "保固費用$23,500、保固負債準備$8,200", "保固費用$23,500、保固負債準備$23,500"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:24+00:00", "source_pdf_sha1": "3919d42dceee", "answer_pdf_sha1": "55ed3776824a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "223", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00022', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-114-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '甲公司收到乙銀行寄來8月份銀行對帳單，8月底銀行對帳單存款餘額為$24,500。經核對帳 列銀行存款相關資料，得知：截至8月底有在途存款$5,800、未兌現支票$4,700；客戶繳付支 票$1,800因存款不足被退票、銀行扣除8月份服務手續費$560，甲公司均尚未入帳；乙銀行 誤將丙公司已兌現支票$300自甲公司存款中扣除；另外，甲公司開立支票$820支付貨款並已 兌現，但甲公司帳列金額誤記為$280。甲公司於8月底未調整前之帳列銀行存款餘額為多少？', '["$25,900", "$27,720", "$28,200", "$28,800 22340"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:24+00:00", "source_pdf_sha1": "3919d42dceee", "answer_pdf_sha1": "55ed3776824a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "223", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00023', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-114-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '甲公司為咖啡豆供應商，於X1年1月與乙咖啡廳簽訂銷貨合約，甲公司以每磅價格$200供 應咖啡豆給乙客戶，並約定若客戶該年總購買量超過500磅，則每磅可降價$10，並追溯至先 前已供應之500磅，且於確定超過500磅時讓客戶可用先前超額繳付之貨款抵繳應支付現金。 甲公司於X1年第一季供應80磅咖啡豆給乙客戶，並收取現金，且經評估後判斷乙客戶當年 購買量不會超過500磅。乙客戶積極展店，擴大營業規模，於X1年第二季又向甲公司購買 咖啡豆300磅，並支付現金。甲公司於第二季再度評估，預估乙客戶X1年之總購買量極有 可能超過500磅。甲公司於X1年第三季又再出售250磅咖啡豆給乙客戶，並收取剩餘應收 現金。有關甲公司之敘述，下列何者錯誤？', '["第二季收現$57,000", "第二季銷貨收入$56,200", "第三季收現$43,700", "第三季銷貨收入$47,500"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:24+00:00", "source_pdf_sha1": "3919d42dceee", "answer_pdf_sha1": "55ed3776824a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "223", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00024', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-114-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '甲公司於 X1 年 1 月 1 日以$360,000 購入乙公司 30%普通股股權，當日乙公司之淨資產為 $1,000,000，經分析得知乙公司可辨認資產中有折舊性資產帳面價值低估$150,000，使用年限10 年，無殘值，採直線法攤銷；另有一批存貨帳面金額低估$50,000，該批存貨已於X1年4月出 售。乙公司在X1年6月15日發放現金股利$12,000，且於X1年底列報本期淨利$200,000。 甲公司X1年底採用權益法之投資的帳列金額應為多少？', '["$356,400", "$396,900", "$416,400", "$434,100"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:24+00:00", "source_pdf_sha1": "3919d42dceee", "answer_pdf_sha1": "55ed3776824a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "223", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL)
